diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..8ece62fbf7a6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1906,8 +1906,57 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(X+C2) --> (C-C2)-X
     if (match(Op1, m_Add(m_Value(X), m_ImmConstant(C2))))
       return BinaryOperator::CreateSub(ConstantExpr::getSub(C, C2), X);
-  }

+    // C - ((C3 -nuw X) & C2) --> (C - (C2 & C3)) + (X & C2) when:
+    // (C3 - ((C2 & C3) - 1)) is pow2
+    // ((C2 + C3) & ((C2 & C3) - 1)) == ((C2 & C3) - 1)
+    // This transformation is valid when the subtraction with the masked value
+    // can be rewritten as an addition with the masked input.
+    if (auto *CInt = dyn_cast<ConstantInt>(C)) {
+      const APInt *MaskC, *SubC;
+      Value *InnerX;
+      Instruction *InnerSub;
+      if (match(Op1, m_OneUse(m_And(m_OneUse(m_Sub(m_APInt(SubC), m_Value(InnerX))),
+                                     m_APInt(MaskC))))) {
+        InnerSub = cast<Instruction>(cast<Instruction>(Op1)->getOperand(0));
+        APInt CVal = CInt->getValue();
+        APInt AndVal = *SubC & *MaskC;  // C2 & C3
+        APInt Offset = CVal - AndVal;    // C - (C2 & C3)
+        
+        // Check if transformation is valid:
+        // Condition 1: (C3 - ((C2 & C3) - 1)) is power of 2
+        APInt Cond1 = *SubC - (AndVal - 1);
+        bool cond1 = Cond1.isPowerOf2();
+        
+        // Condition 2: ((C2 + C3) & ((C2 & C3) - 1)) == ((C2 & C3) - 1)
+        APInt Cond2Mask = AndVal - 1;
+        bool cond2 = ((*MaskC + *SubC) & Cond2Mask) == Cond2Mask;
+        
+        // Need nuw on inner sub to ensure X <= C3
+        if (cond1 && cond2 && InnerSub->hasNoUnsignedWrap()) {
+          Instruction *AndOp = BinaryOperator::CreateAnd(InnerX, ConstantInt::get(I.getType(), *MaskC));
+          if (Offset.isZero()) {
+            return AndOp;
+          } else if (Offset.isNegative()) {
+            return BinaryOperator::CreateSub(AndOp, ConstantInt::get(I.getType(), -Offset));
+          } else {
+            return BinaryOperator::CreateAdd(AndOp, ConstantInt::get(I.getType(), Offset));
+          }
+        }
+        
+        // Special case: C3 - C == ~C2 and C2 is of form -2^k
+        // This gives a tighter mask: X & (C | (~C2 << ctz(C2)))
+        APInt Diff = *SubC - CVal;
+        if (Diff == ~(*MaskC) && InnerSub->hasNoUnsignedWrap()) {
+          APInt NotMask = ~(*MaskC);
+          if ((NotMask & (NotMask + 1)).isZero()) {
+            APInt ResultMask = CVal | (Diff << MaskC->countTrailingZeros());
+            return BinaryOperator::CreateAnd(InnerX, ConstantInt::get(I.getType(), ResultMask));
+          }
+        }
+      }
+    }
+  }
   auto TryToNarrowDeduceFlags = [this, &I, &Op0, &Op1]() -> Instruction * {
     if (Instruction *Ext = narrowMathIfNoOverflow(I))
       return Ext;
